package com.chaobo.scm.supplier.application.operations;import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.application.shared.*;import com.chaobo.scm.supplier.domain.shared.IdentifierGenerator;import com.chaobo.scm.supplier.infrastructure.persistence.operations.SupplierOperationsMapper;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.math.BigDecimal;import java.time.LocalDate;import java.util.*;
@Service public class SupplierOperationsApplicationService{private final SupplierOperationsMapper mapper;private final IdentifierGenerator ids;private final AuditLogRepository audit;public SupplierOperationsApplicationService(SupplierOperationsMapper mapper,IdentifierGenerator ids,AuditLogRepository audit){this.mapper=mapper;this.ids=ids;this.audit=audit;}@Transactional public void accept(OperationsEvent e){switch(e.eventType()){case "RfqPublished"->work(e,"QUOTE","RFQ",2);case "SupplierContractSubmitted"->work(e,"CONTRACT_APPROVAL","CONTRACT",1);case "PurchaseOrderReleased"->work(e,"PO_CONFIRM","PURCHASE_ORDER",2);case "SupplierRectificationRequested"->work(e,"RECTIFICATION","QUALITY_ISSUE",2);case "BmsReconciliationIssued"->work(e,"RECONCILIATION","RECONCILIATION",2);case "SupplierReturnConfirmationRequested"->work(e,"RETURN_CONFIRM","SUPPLIER_RETURN",2);case "SupplierQualificationExpiring"->warning(e,"QUALIFICATION_EXPIRING","QUALIFICATION",2);case "SupplierContractExpiring"->warning(e,"CONTRACT_EXPIRING","CONTRACT",2);case "SupplierQuoteExpiring"->warning(e,"QUOTE_EXPIRING","QUOTE",1);case "AsnDelayed","TmsShipmentDelayed","SupplierRectificationOverdue"->warning(e,e.eventType().toUpperCase(),e.businessType(),3);case "SupplierScorePublished"->warning(e,"LOW_SCORE","SCORE_RESULT",2);default->throw new BusinessException(ErrorCode.BUSINESS_RULE_FAILED,"不支持的运营事件: "+e.eventType());}}@Transactional(readOnly=true)public List<OperationViews.WorkItem> workItems(Long supplierId,Long scope,Integer status,int page,int size){check(page,size);return mapper.workItems(scope==null?supplierId:scope,status,(page-1)*size,size);}@Transactional(readOnly=true)public List<OperationViews.Warning> warnings(Long supplierId,Long scope,Integer status,int page,int size){check(page,size);return mapper.warnings(scope==null?supplierId:scope,status,(page-1)*size,size);}@Transactional public void processWork(long id,int version,boolean close,CommandContext c){c.requirePermission("supplier:work-item:process");if(mapper.processWork(id,version,close?4:3)!=1)throw conflict();audit.save(c,"PROCESS_WORK_ITEM","WORK_ITEM",id,String.valueOf(id),null,"{\"status\":"+(close?4:3)+"}");}@Transactional public void processWarning(long id,int version,boolean close,CommandContext c){c.requirePermission("supplier:warning:process");if(mapper.processWarning(id,version,close?3:2)!=1)throw conflict();audit.save(c,"PROCESS_WARNING","WARNING",id,String.valueOf(id),null,"{\"status\":"+(close?3:2)+"}");}@Transactional(readOnly=true)public List<OperationViews.FailedEvent> failedEvents(){var all=new ArrayList<OperationViews.FailedEvent>();all.addAll(mapper.failedInbound(100));all.addAll(mapper.failedOutbound(100));all.sort(Comparator.comparing(OperationViews.FailedEvent::updatedAt).reversed());return all;}@Transactional public void replay(long id,String direction,String reason,CommandContext c){c.requirePermission("supplier:event:replay");if(reason==null||reason.isBlank())throw rule("人工重放必须说明原因");int changed="OUTBOUND".equals(direction)?mapper.replayOutbound(id,reason):mapper.replayInbound(id,reason);if(changed!=1)throw conflict();audit.save(c,"REPLAY_"+direction+"_EVENT","EVENT",id,String.valueOf(id),null,"{\"reason\":\""+reason.replace("\"","")+"\"}");}@Transactional public void reconcile(String type,String target,LocalDate date,long remoteCount,BigDecimal remoteAmount,CommandContext c){c.requirePermission("supplier:data-reconciliation:execute");long localCount;BigDecimal localAmount=null;switch(type){case "ASN"->localCount=mapper.localAsnCount(date);case "SUPPLIER_RETURN"->localCount=mapper.localReturnCount(date);case "STATEMENT"->{localCount=mapper.localStatementCount(date);localAmount=mapper.localStatementAmount(date);}default->throw rule("不支持的对账类型");}boolean amountSame=localAmount==null||remoteAmount!=null&&localAmount.compareTo(remoteAmount)==0,same=localCount==remoteCount&&amountSame;String detail=same?null:"本地数量="+localCount+"，对方数量="+remoteCount+(localAmount==null?"":"，本地金额="+localAmount+"，对方金额="+remoteAmount);mapper.upsertReconciliation(ids.nextId(),type,target,date,localCount,remoteCount,localAmount,remoteAmount,detail,same?1:2,c.operatorId());}@Transactional(readOnly=true)public List<OperationViews.Reconciliation> reconciliations(){return mapper.reconciliations();}@Transactional(readOnly=true)public OperationViews.Dashboard dashboard(){return mapper.dashboard();}private void work(OperationsEvent e,String type,String business,int assignee){mapper.insertWork(ids.nextId(),type,e.supplierId(),business,e.businessId(),e.businessNo(),e.message(),assignee,e.dueAt(),e.eventCode());}private void warning(OperationsEvent e,String type,String business,int level){mapper.insertWarning(ids.nextId(),type,e.supplierId(),business,e.businessId(),level,e.message(),e.occurredAt(),e.eventCode());}private static void check(int p,int s){if(p<1||s<1||s>100)throw rule("分页参数不合法");}private static BusinessException rule(String m){return new BusinessException(ErrorCode.BUSINESS_RULE_FAILED,m);}private static BusinessException conflict(){return new BusinessException(ErrorCode.VERSION_CONFLICT,"状态或版本已变更");}}
